import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  LineChart, Line,
  BarChart, Bar,
  XAxis, YAxis, Tooltip, Legend, CartesianGrid, ResponsiveContainer
} from "recharts";
import "./PriceAnalytics.css";

const API_BASE = "http://localhost:7000/api";

export default function PriceAnalytics() {
  const [categoryList, setCategoryList] = useState([]);
  const [productList, setProductList] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState("");
  const [selectedProduct, setSelectedProduct] = useState("");
  const [graphData, setGraphData] = useState([]);

  // 🔹 Fetch initial data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [productsRes, catsRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`)
        ]);

        const productsData = Array.isArray(productsRes.data)
          ? productsRes.data
          : productsRes.data?.prices || productsRes.data?.items || [];

        const categoriesData = Array.isArray(catsRes.data)
          ? catsRes.data
          : catsRes.data?.categories || [];

        setProductList(productsData);
        setCategoryList(categoriesData);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  // 🔹 Simulated Graph Data (replace with backend stats later)
  useEffect(() => {
    // Example static chart data (you can map backend data here)
    const dummyData = [
      { name: "Mon", price: 20, sales: 40 },
      { name: "Tue", price: 35, sales: 60 },
      { name: "Wed", price: 30, sales: 50 },
      { name: "Thu", price: 45, sales: 70 },
      { name: "Fri", price: 25, sales: 40 },
      { name: "Sat", price: 50, sales: 80 },
      { name: "Sun", price: 40, sales: 60 },
    ];
    setGraphData(dummyData);
  }, [selectedCategory, selectedProduct]);

  return (
    <div className="price-analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>

      {/* Filters Section */}
      <div className="filter-box">
        <div>
          <label>Category:</label>
          <select
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            <option value="">All Categories</option>
            {Array.isArray(categoryList) &&
              categoryList.map((c) => (
                <option key={c._id} value={c.name}>
                  {c.name}
                </option>
              ))}
          </select>
        </div>

        <div>
          <label>Product:</label>
          <select
            value={selectedProduct}
            onChange={(e) => setSelectedProduct(e.target.value)}
          >
            <option value="">All Products</option>
            {Array.isArray(productList) &&
              productList.map((p) => (
                <option key={p._id || p.name} value={p.name}>
                  {p.name}
                </option>
              ))}
          </select>
        </div>
      </div>

      {/* Graph Section */}
      <div className="graph-card">
        <h3>Weekly Price & Sales Trend</h3>
        {graphData.length > 0 ? (
          <ResponsiveContainer width="100%" height={350}>
            <ComposedChart data={graphData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="sales" barSize={30} fill="#82ca9d" radius={6} />
              <Line
                type="monotone"
                dataKey="price"
                stroke="#8884d8"
                strokeWidth={3}
                activeDot={{ r: 8 }}
              />
            </ComposedChart>
          </ResponsiveContainer>
        ) : (
          <p className="no-data">No data available to display</p>
        )}
      </div>
    </div>
  );
}
